/// <summary>
/// Extension of the <c>SalesAgreementHeader</c> datasource in the <c>SalesAgreementCreate</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formDataSourceStr(SalesAgreementCreate, SalesAgreementHeader))]
final class SalesAgreementCreateSalesAgreementHeaderETGSPAIN_Extension
{    
}

Method.Source:
/// <summary>
/// Extension of the <c>initValue</c> method.
/// </summary>
public void initValue()
{
    next initValue();

    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    if (currentCompanyIsSpanishCompany)
    {
        FormRun                 formRun                 = this.formRun();
        AgreementFormArgs       salesAgreementFormArgs  = formRun.parmSalesAgreementFormArgs();
        SalesAgreementHeader    salesAgreementHeader    = this.cursor() as SalesAgreementHeader;

        salesAgreementHeader.DefaultAgreementLineExpirationDate = dateMax();

        switch (salesAgreementFormArgs.parmCallerDataSet())
        {
            case tableNum(ETGSPAINPurchOperationTable):

                SalesAgreementHeader::ETGSPAINmandatoryOperationFields(formRun);

                ETGSPAINPurchOperationTable ETGSPAINPurchOperationTable = salesAgreementFormArgs.parmCallerRecord() as ETGSPAINPurchOperationTable;

                salesAgreementHeader.ETGSPAINAgreementOperationId = ETGSPAINPurchOperationTable.OperationId;

                break;
        }
    }
}

/// <summary>
/// Extension of the <c>active</c> method.
/// </summary>
/// <returns>
/// Returns an integer indicating the result of the operation.
/// </returns>
public int active()    
{
    int     ret                             = next active();        
    FormRun formRun                         = this.formRun() as FormRun;
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    if (currentCompanyIsSpanishCompany)
    {
        SalesAgreementHeader::ETGSPAINmandatoryOperationFields(formRun);
    }

    return ret;
}

/// <summary>
/// EventHandler that is triggered whenever the <c>ETGSPAINSalesAgreementOperationId</c> field is modified.
/// </summary>
/// <param name="_sender">FormDataObject.</param>
/// <param name="_e">FormDataFieldEventArgs.</param>
[FormDataSourceEventHandler(formDataSourceStr(SalesAgreementCreate, SalesAgreementHeader), FormDataSourceEventType::ValidatedWrite)]
public static void SalesAgreementHeader_OnValidatedWrite(FormDataSource _sender, FormDataSourceEventArgs _e)
{             
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    if (currentCompanyIsSpanishCompany)
    {
        FormRun                 formRun = _sender.formRun();
        SalesAgreementHeader::ETGSPAINmandatoryOperationFields(formRun);
    }
}
